if (! function_exists('redis_client')) {
    function redis_client($command, $host = null, $port = null, $password = null, $database = null, $timeout = null, $retry = null)
    {
        // Redis client using the PHP Redis extension
        // Supports all Redis commands through a unified interface

        // Validate inputs
        $host = isset($host) ? (string)$host : '127.0.0.1';
        $port = isset($port) ? (int)$port : 6379;
        $timeout = isset($timeout) ? min(max((float)$timeout, 0.5), 30.0) : 5.0;
        $database = isset($database) ? min(max((int)$database, 0), 15) : 0;
        $retry = isset($retry) ? min(max((int)$retry, 0), 3) : 1;
        $cmd = isset($command) ? trim((string)$command) : '';
        $password = isset($password) ? (string)$password : '';

        if ($cmd === '') {
            return ['error' => 'Empty command', 'result' => null];
        }

        // Check if Redis extension is available
        if (!extension_loaded('redis')) {
            return ['error' => 'Redis PHP extension is not loaded', 'result' => null];
        }

        // Parse command respecting quoted strings (like shell arguments)
        $parts = str_getcsv($cmd, ' ');
        $command_name = strtoupper($parts[0]);
        $args = array_slice($parts, 1);

        $last_error = '';
        $attempts = 0;

        while ($attempts <= $retry) {
            $attempts++;
            
            try {
                $redis = new Redis();
                $connected = @$redis->connect($host, $port, $timeout);
                
                if (!$connected) {
                    $last_error = "Connection failed to {$host}:{$port} (attempt {$attempts})";
                    if ($attempts <= $retry) {
                        usleep(200000);
                    }
                    continue;
                }
                
                // Authenticate if password provided
                if ($password !== '') {
                    if (!$redis->auth($password)) {
                        $redis->close();
                        return ['error' => 'AUTH failed: invalid password', 'result' => null];
                    }
                }
                
                // Select database
                if ($database > 0) {
                    $redis->select($database);
                }
                
                // Execute command via switch
                $result = null;
                $result_type = 'unknown';
                
                switch ($command_name) {
                    // --- Connection ---
                    case 'PING':
                        $result = $redis->ping();
                        $result_type = 'string';
                        break;
                        
                    case 'ECHO':
                        $result = count($args) >= 1 ? $redis->echo($args[0]) : false;
                        $result_type = 'string';
                        break;
                        
                    case 'SELECT':
                        $result = count($args) >= 1 ? $redis->select((int)$args[0]) : false;
                        $result_type = 'status';
                        break;
                        
                    case 'AUTH':
                        $result = count($args) >= 1 ? $redis->auth(implode(' ', $args)) : false;
                        $result_type = 'status';
                        break;
                        
                    // --- Keys ---
                    case 'KEYS':
                        $result = $redis->keys(count($args) >= 1 ? $args[0] : '*');
                        $result_type = 'array';
                        break;
                        
                    case 'GET':
                        $result = count($args) >= 1 ? $redis->get($args[0]) : null;
                        $result_type = 'string_or_null';
                        break;
                        
                    case 'SET':
                        $result = count($args) >= 2 ? $redis->set($args[0], $args[1]) : false;
                        $result_type = 'status';
                        break;
                        
                    case 'SETEX':
                        $result = count($args) >= 3 ? $redis->setex($args[0], (int)$args[1], $args[2]) : false;
                        $result_type = 'status';
                        break;
                        
                    case 'DEL':
                        $result = count($args) >= 1 ? $redis->del(...$args) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'EXISTS':
                        $result = count($args) >= 1 ? $redis->exists(...$args) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'EXPIRE':
                        $result = count($args) >= 2 ? $redis->expire($args[0], (int)$args[1]) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'TTL':
                        $result = count($args) >= 1 ? $redis->ttl($args[0]) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'TYPE':
                        $result = count($args) >= 1 ? $redis->type($args[0]) : false;
                        $result_type = 'string';
                        break;
                        
                    // --- Strings ---
                    case 'INCR':
                        $result = count($args) >= 1 ? $redis->incr($args[0]) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'INCRBY':
                        $result = count($args) >= 2 ? $redis->incrBy($args[0], (int)$args[1]) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'DECR':
                        $result = count($args) >= 1 ? $redis->decr($args[0]) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'MGET':
                        $result = count($args) >= 1 ? $redis->mget($args) : [];
                        $result_type = 'array';
                        break;
                        
                    case 'MSET':
                        if (count($args) >= 2 && count($args) % 2 === 0) {
                            $kv = [];
                            for ($i = 0; $i < count($args); $i += 2) {
                                $kv[$args[$i]] = $args[$i+1];
                            }
                            $result = $redis->mset($kv);
                        } else {
                            $result = false;
                        }
                        $result_type = 'status';
                        break;
                        
                    // --- Lists ---
                    case 'LPUSH':
                        $result = count($args) >= 1 ? $redis->lPush($args[0], ...array_slice($args, 1)) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'RPUSH':
                        $result = count($args) >= 1 ? $redis->rPush($args[0], ...array_slice($args, 1)) : false;
                        $result_type = 'integer';
                        break;
                        
                    case 'LPOP':
                        $result = count($args) >= 1 ? $redis->lPop($args[0]) : false;
                        $result_type = 'string_or_null';
                        break;
                        
                    case 'RPOP':
                        $result = count($args) >= 1 ? $redis->rPop($args[0]) : false;
                        $result_type = 'string_or_null';
                        break;
                        
                    case 'LLEN':
                        $result = count($args) >= 1 ? $redis->lLen($args[0]) : false;
                        $result_type = 'integer';
                        break;
                        
