                        $result = count($args) >= 3 ? $redis->lRange($args[0], (int)$args[1], (int)$args[2]) : false;
                        $result_type = 'array';
                        break;
                        
                    // --- Sets ---
                    case 'SADD':
                        $result = count($args) >= 1 ? $redis->sAdd($args[0], ...array_slice($args, 1)) : false;
                        $result_type = 'integer';
