                    // --- Server ---
                    case 'INFO':
                        $result = $redis->info(count($args) >= 1 ? $args[0] : null);
                        $result_type = 'array';
                        break;
                        
                    case 'DBSIZE':
                        $result = $redis->dbSize();
                        $result_type = 'integer';
                        break;
                        
                    case 'FLUSHDB':
                        $result = $redis->flushDB();
                        $result_type = 'status';
