                    case 'DISCARD':
                        $result = $redis->discard();
                        $result_type = 'status';
                        break;
                        
                    default:
                        // Try rawCommand as fallback
                        try {
                            $result = @$redis->rawCommand($command_name, ...$args);
                            $result_type = 'raw';
                        } catch (\Throwable $e) {
